const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const lerp = (start, end, t) => start + (end - start) * t;

const hexToSrgb = (hex) => {
  const r = parseInt(hex.slice(1, 3), 16) / 255;
  const g = parseInt(hex.slice(3, 5), 16) / 255;
  const b = parseInt(hex.slice(5, 7), 16) / 255;
  return [r, g, b];
};

const srgbToLinear = (value) => {
  if (value <= 0.04045) return value / 12.92;
  return Math.pow((value + 0.055) / 1.055, 2.4);
};

const linearToSrgb = (value) => {
  if (value <= 0.0031308) return 12.92 * value;
  return 1.055 * Math.pow(value, 1 / 2.4) - 0.055;
};

const srgbToOklch = (r, g, b) => {
  const lr = srgbToLinear(r);
  const lg = srgbToLinear(g);
  const lb = srgbToLinear(b);

  const l = 0.4122214708 * lr + 0.5363325363 * lg + 0.0514459929 * lb;
  const m = 0.2119034982 * lr + 0.6806995451 * lg + 0.1073969566 * lb;
  const s = 0.0883024619 * lr + 0.2817188376 * lg + 0.6299787005 * lb;

  const lRoot = Math.cbrt(l);
  const mRoot = Math.cbrt(m);
  const sRoot = Math.cbrt(s);

  const L = 0.2104542553 * lRoot + 0.793617785 * mRoot - 0.0040720468 * sRoot;
  const a = 1.9779984951 * lRoot - 2.428592205 * mRoot + 0.4505937099 * sRoot;
  const b2 = 0.0259040371 * lRoot + 0.7827717662 * mRoot - 0.808675766 * sRoot;

  const C = Math.sqrt(a * a + b2 * b2);
  const h = Math.atan2(b2, a);
  return { L, C, h };
};

const oklchToSrgb = (L, C, h) => {
  const a = C * Math.cos(h);
  const b = C * Math.sin(h);

  const lRoot = L + 0.3963377774 * a + 0.2158037573 * b;
  const mRoot = L - 0.1055613458 * a - 0.0638541728 * b;
  const sRoot = L - 0.0894841775 * a - 1.291485548 * b;

  const l = lRoot * lRoot * lRoot;
  const m = mRoot * mRoot * mRoot;
  const s = sRoot * sRoot * sRoot;

  const lr = 4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s;
  const lg = -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s;
  const lb = -0.0041960863 * l - 0.7034186147 * m + 1.707614701 * s;

  return [linearToSrgb(lr), linearToSrgb(lg), linearToSrgb(lb)];
};

const isInGamut = (rgb) => rgb.every((value) => value >= 0 && value <= 1);

const rgbToHex = (rgb) => {
  const [r, g, b] = rgb.map((value) => Math.round(clamp(value, 0, 1) * 255));
  const toHex = (value) => value.toString(16).padStart(2, '0');
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
};

const oklchToHexFitted = (L, C, h) => {
  let chroma = Math.max(0, C);
  for (let i = 0; i < 24; i += 1) {
    const rgb = oklchToSrgb(L, chroma, h);
    if (isInGamut(rgb)) {
      return rgbToHex(rgb);
    }
    chroma *= 0.9;
  }
  return rgbToHex(oklchToSrgb(L, 0, h));
};

export const generateColorScheme = (hexColor) => {
  const [r, g, b] = hexToSrgb(hexColor);
  const input = srgbToOklch(r, g, b);

  const scale = [50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950];
  const colors = scale.map((step) => {
    let targetL;
    let targetC;

    if (step <= 500) {
      const t = (step - 50) / 450;
      targetL = lerp(0.97, input.L, t);
      targetC = lerp(0.008, input.C, t);
    } else {
      const t = (step - 500) / 450;
      targetL = lerp(input.L, 0.22, t);
      targetC = lerp(input.C, Math.min(0.03, input.C * 0.35), t);
    }

    const color = oklchToHexFitted(clamp(targetL, 0, 1), Math.max(0, targetC), input.h);
    return { step, color };
  });

  return [{ step: '0', color: '#ffffff' }, ...colors];
};
