import { computed, ref } from 'vue';
import { useAppStore } from '@/store/app/app.js';
import { lmnFetch } from '@/assets/js/functions/lmnFetch.js';
import { isObject } from '@/assets/js/functions/isObject.js';
import { notify } from '@/assets/js/functions/notify.js';

const decodeHTMLEntities = (text) => {
  const textArea = document.createElement('textarea');
  textArea.innerHTML = text;
  return textArea.value;
};

const stripProtectedFields = (settings) => {
  const settingsCopy = JSON.parse(JSON.stringify(settings || {}));
  delete settingsCopy.google_analytics_service_account;
  return settingsCopy;
};

const normalizeScale = (scale) => {
  if (Array.isArray(scale)) return scale;
  if (scale && typeof scale === 'object') {
    return Object.values(scale);
  }
  return [];
};

const normalizeSettingsShape = (rawSettings) => {
  const normalized = { ...(rawSettings || {}) };
  normalized.base_theme_scale = normalizeScale(normalized.base_theme_scale);
  normalized.accent_theme_scale = normalizeScale(normalized.accent_theme_scale);
  return normalized;
};

/**
 * Schema-aligned type map for uixpress_settings (matches GlobalOptions.php).
 * Ensures payload structure matches WordPress REST API expectations.
 */
const SETTINGS_SCHEMA = {
  string: [
    'license_key', 'instance_id', 'plugin_name', 'logo', 'dark_logo', 'login_image',
    'base_theme_color', 'accent_theme_color', 'login_path', 'layout', 'admin_favicon',
    'force_global_theme', 'submenu_style', 'analytics_provider', 'google_analytics_property_id',
    'remote_site_switcher_capability', 'custom_font_source', 'custom_font_family', 'custom_font_url',
    'activity_log_level', 'turnstyle_site_key', 'turnstyle_secret_key',
  ],
  boolean: [
    'auto_dark', 'hide_screenoptions', 'hide_help_toggle', 'style_login', 'disable_search',
    'enable_turnstyle', 'enable_admin_menu_search', 'hide_language_selector',
    'use_classic_post_tables', 'use_modern_plugin_page', 'use_custom_dashboard',
    'enable_uixpress_analytics', 'use_modern_media_page', 'use_modern_users_page',
    'use_modern_comments_page', 'use_modern_post_editor', 'enable_realtime_collaboration',
    'enable_svg_uploads', 'enable_font_uploads', 'enable_database_explorer',
    'enable_role_editor', 'enable_custom_post_types', 'enable_activity_logger',
    'activity_log_auto_cleanup',
  ],
  integer: ['activity_log_retention_days'],
  array: [
    'disable_theme', 'search_post_types', 'base_theme_scale', 'accent_theme_scale',
    'text_replacements', 'external_stylesheets', 'magic_dark_mode_pages', 'remote_sites',
    'modern_post_editor_post_types', 'custom_font_files',
  ],
};

const toBool = (v) => v === true || v === 'true' || v === 1 || v === '1';
const toInt = (v) => (v == null || v === '' ? undefined : Math.max(0, parseInt(v, 10) || 0));
const toStr = (v) => (v == null ? '' : String(v));
const toArray = (v) => (Array.isArray(v) ? v : v && typeof v === 'object' ? Object.values(v) : []);

const sanitizeArrayItem = (item, schema) => {
  if (!item || typeof item !== 'object') return null;
  const out = {};
  for (const [k, type] of Object.entries(schema)) {
    if (item[k] != null) out[k] = type === 'string' ? toStr(item[k]) : item[k];
  }
  return Object.keys(out).length ? out : null;
};

/**
 * Prepares settings for API save - ensures types match schema and strips invalid values.
 */
const prepareSettingsForApi = (raw) => {
  if (!raw || typeof raw !== 'object') return {};
  const out = {};

  for (const key of SETTINGS_SCHEMA.string) {
    if (raw[key] != null) out[key] = toStr(raw[key]);
  }
  for (const key of SETTINGS_SCHEMA.boolean) {
    if (raw[key] != null) out[key] = toBool(raw[key]);
  }
  for (const key of SETTINGS_SCHEMA.integer) {
    if (raw[key] != null) out[key] = toInt(raw[key]);
  }
  for (const key of SETTINGS_SCHEMA.array) {
    if (raw[key] == null) continue;
    const arr = toArray(raw[key]);
    if (key === 'base_theme_scale' || key === 'accent_theme_scale') {
      out[key] = arr
        .map((item) => sanitizeArrayItem(item, { step: 'string', color: 'string' }))
        .filter(Boolean);
    } else if (key === 'disable_theme') {
      out[key] = arr
        .map((item) => sanitizeArrayItem(item, { id: 'string', value: 'string', type: 'string' }))
        .filter(Boolean);
    } else if (key === 'search_post_types' || key === 'modern_post_editor_post_types') {
      out[key] = arr
        .map((item) => sanitizeArrayItem(item, { slug: 'string', name: 'string', rest_base: 'string' }))
        .filter(Boolean);
    } else if (key === 'text_replacements') {
      out[key] = arr
        .filter((p) => Array.isArray(p) && p.length >= 2 && p[0] && p[1])
        .map((p) => [toStr(p[0]), toStr(p[1])]);
    } else if (key === 'external_stylesheets') {
      out[key] = arr.filter((v) => typeof v === 'string' && v.trim());
    } else if (key === 'magic_dark_mode_pages') {
      out[key] = arr.filter((v) => typeof v === 'string' && v.trim());
    } else if (key === 'remote_sites') {
      out[key] = arr
        .map((item) =>
          item && typeof item === 'object' && item.url
            ? {
                url: toStr(item.url),
                username: toStr(item.username || ''),
                app_password: toStr(item.app_password || ''),
              }
            : null
        )
        .filter(Boolean);
    } else if (key === 'custom_font_files') {
      out[key] = arr
        .map((item) =>
          item && typeof item === 'object' && item.url
            ? {
                url: toStr(item.url),
                weight: toStr(item.weight || '400'),
                style: toStr(item.style || 'normal'),
              }
            : null
        )
        .filter(Boolean);
    } else {
      out[key] = arr;
    }
  }

  if (raw.custom_css != null) out.custom_css = toStr(raw.custom_css);

  return out;
};

export const useSettingsData = () => {
  const appStore = useAppStore();
  const loading = ref(false);
  const saving = ref(false);
  const saveQueued = ref(false);
  const settingsUploader = ref(null);

  // Initialize from app store (server-injected via script tag) so saved settings
  // display immediately on page load before the API fetch completes
  const initialFromStore = appStore.state?.uixpress_settings;
  const normalized = isObject(initialFromStore)
    ? normalizeSettingsShape(initialFromStore)
    : {};
  if (normalized.custom_css) {
    normalized.custom_css = decodeHTMLEntities(normalized.custom_css);
  }
  const settings = ref(normalized);
  const originalSettings = ref(JSON.parse(JSON.stringify(normalized)));
  const settingsFetched = ref(Object.keys(normalized).length > 0);

  const hasUnsavedChanges = computed(() => {
    return JSON.stringify(settings.value) !== JSON.stringify(originalSettings.value);
  });

  const loadSettings = async () => {
    loading.value = true;
    appStore.updateState('loading', true);

    try {
      const response = await lmnFetch({ endpoint: 'wp/v2/settings', params: {} });
      if (!response?.data?.uixpress_settings) return false;
      if (!isObject(response.data.uixpress_settings)) return false;

      settings.value = normalizeSettingsShape(response.data.uixpress_settings);
      appStore.updateState('uixpress_settings', settings.value);

      if (settings.value.custom_css) {
        settings.value.custom_css = decodeHTMLEntities(settings.value.custom_css);
      }

      originalSettings.value = JSON.parse(JSON.stringify(settings.value));
      settingsFetched.value = true;

      return true;
    } catch (error) {
      notify({
        type: 'error',
        title: __('Failed to load settings', 'uixpress'),
      });
      return false;
    } finally {
      loading.value = false;
      appStore.updateState('loading', false);
    }
  };

  const saveSettings = async () => {
    if (saving.value) {
      saveQueued.value = true;
      return false;
    }

    let savedAtLeastOnce = false;
    do {
      saveQueued.value = false;
      saving.value = true;
      appStore.updateState('loading', true);

      try {
        const normalizedSettings = normalizeSettingsShape(settings.value);
        settings.value = normalizedSettings;

        const apiPayload = prepareSettingsForApi(normalizedSettings);
        const payload = {
          uixpress_settings: stripProtectedFields(apiPayload),
        };

        const response = await lmnFetch({
          endpoint: 'wp/v2/settings',
          type: 'POST',
          params: {},
          data: payload,
        });

        if (!response?.data) {
          notify({
            type: 'error',
            title: __('Unable to save settings', 'uixpress'),
          });
          continue;
        }

        originalSettings.value = JSON.parse(JSON.stringify(settings.value));
        appStore.updateState('uixpress_settings', settings.value);
        notify({ title: __('Settings updated!', 'uixpress'), type: 'success' });
        savedAtLeastOnce = true;
      } catch (error) {
        notify({
          type: 'error',
          title: __('Unable to save settings', 'uixpress'),
        });
      } finally {
        saving.value = false;
        appStore.updateState('loading', false);
      }
    } while (saveQueued.value);

    return savedAtLeastOnce;
  };

  const exportSettings = () => {
    const payload = {
      uixpress_settings: JSON.parse(JSON.stringify(settings.value)),
    };

    delete payload.uixpress_settings.license_key;
    delete payload.uixpress_settings.instance_id;

    const jsonString = JSON.stringify(payload, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = 'uixpress-settings.json';

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const importFromSettingJSON = async (file) => {
    if (!file || !(file instanceof File)) {
      notify({
        type: 'error',
        title: __('Please provide a valid JSON file', 'uixpress'),
      });
      return false;
    }

    const fileContent = await file.text();
    const jsonData = JSON.parse(fileContent);

    if (
      !jsonData.uixpress_settings ||
      typeof jsonData.uixpress_settings !== 'object' ||
      jsonData.uixpress_settings === null
    ) {
      notify({
        type: 'error',
        title: __('Invalid settings: must be an object', 'uixpress'),
      });
      return false;
    }

    settings.value = {
      ...settings.value,
      ...jsonData.uixpress_settings,
    };

    return true;
  };

  const handleSettingsFileUpload = async (event) => {
    const file = event?.target?.files?.[0];
    try {
      const imported = await importFromSettingJSON(file);
      if (imported) {
        notify({ type: 'success', title: __('Settings imported', 'uixpress') });
      } else {
        notify({ type: 'error', title: __('Import failed', 'uixpress') });
      }
    } catch (error) {
      notify({ type: 'error', title: __('Import failed', 'uixpress') });
    }
  };

  return {
    loading,
    saving,
    settingsFetched,
    settingsUploader,
    settings,
    originalSettings,
    hasUnsavedChanges,
    loadSettings,
    saveSettings,
    exportSettings,
    importFromSettingJSON,
    handleSettingsFileUpload,
  };
};
