import { watch } from 'vue';
import { hexToRgb } from '@/assets/js/functions/hexToRgb.js';
import { generateColorScheme } from './generateColorScheme.js';

const normalizeHex = (value) => {
  if (!value || typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed.startsWith('#')) return null;
  if (/^#[0-9a-fA-F]{6}$/.test(trimmed)) return trimmed;
  if (/^#[0-9a-fA-F]{3}$/.test(trimmed)) {
    const r = trimmed[1] + trimmed[1];
    const g = trimmed[2] + trimmed[2];
    const b = trimmed[3] + trimmed[3];
    return `#${r}${g}${b}`;
  }
  return null;
};

const updateCssProperties = (cssValues, colorName) => {
  const safeValues = Array.isArray(cssValues)
    ? cssValues
    : cssValues && typeof cssValues === 'object'
    ? Object.values(cssValues)
    : [];
  for (const color of safeValues) {
    if (!color?.color || !color?.step) continue;
    const hexArray = hexToRgb(color.color);
    const variableName = `--uix-${colorName}-${color.step}`;
    document.documentElement.style.setProperty(
      variableName,
      hexArray.join(' ')
    );
  }
};

export const useThemeScales = ({ settings, settingsFetched }) => {
  watch(
    () => [settingsFetched.value, settings.value?.base_theme_color],
    ([ready, color]) => {
      if (!ready) return;
      const normalized = normalizeHex(color);
      if (!normalized) return;
      settings.value.base_theme_scale = generateColorScheme(normalized);
      updateCssProperties(settings.value.base_theme_scale, 'base');
    },
    { immediate: true }
  );

  watch(
    () => [settingsFetched.value, settings.value?.accent_theme_color],
    ([ready, color]) => {
      if (!ready) return;
      const normalized = normalizeHex(color);
      if (!normalized) return;
      settings.value.accent_theme_scale = generateColorScheme(normalized);
      updateCssProperties(settings.value.accent_theme_scale, 'accent');
    },
    { immediate: true }
  );

  watch(
    () => settings.value?.base_theme_scale,
    (baseScale) => {
      if (!settingsFetched.value) return;
      updateCssProperties(baseScale, 'base');
    },
    { deep: true }
  );

  watch(
    () => settings.value?.accent_theme_scale,
    (accentScale) => {
      if (!settingsFetched.value) return;
      updateCssProperties(accentScale, 'accent');
    },
    { deep: true }
  );
};
