<script setup>
import { computed } from 'vue';
import ColorPicker from '@/components/utility/color-select/index.vue';
import AppButton from '@/components/utility/app-button/index.vue';
import { generateColorScheme } from '../generateColorScheme.js';

const props = defineProps({
  setting: {
    type: Object,
    required: true,
  },
  modelValue: {
    type: Object,
    required: true,
  },
});

const emit = defineEmits(['update:modelValue']);

const colorKey = computed(() => props.setting.customProps.colorKey);
const scaleKey = computed(() => props.setting.customProps.scaleKey);
const scaleLabel = computed(() => props.setting.customProps.scaleLabel);

const normalizeScale = (scale) => {
  if (Array.isArray(scale)) return scale;
  if (scale && typeof scale === 'object') return Object.values(scale);
  return [];
};

const baseColor = computed({
  get: () => props.modelValue[colorKey.value],
  set: (value) => {
    const updated = {
      ...props.modelValue,
      [colorKey.value]: value,
    };

    if (
      typeof value === 'string' &&
      /^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(value.trim())
    ) {
      updated[scaleKey.value] = generateColorScheme(value.trim());
    }

    emit('update:modelValue', {
      ...updated,
    });
  },
});

const colorScale = computed({
  get: () => normalizeScale(props.modelValue[scaleKey.value]),
  set: (value) => {
    emit('update:modelValue', {
      ...props.modelValue,
      [scaleKey.value]: value,
    });
  },
});

const clearColors = () => {
  emit('update:modelValue', {
    ...props.modelValue,
    [scaleKey.value]: [],
    [colorKey.value]: '',
  });
};

const updateScaleColor = (index, val) => {
  const currentScale = normalizeScale(props.modelValue[scaleKey.value]);
  const updated = [...currentScale];
  updated[index] = { ...updated[index], color: val };
  emit('update:modelValue', {
    ...props.modelValue,
    [scaleKey.value]: updated,
  });
};
</script>

<template>
  <div class="col-span-2">
    <div class="max-w-[400px] flex flex-col gap-1">
      <div class="grid grid-cols-3 gap-3">
        <span class="flex flex-col place-content-center">{{ scaleLabel }}</span>
        <ColorPicker v-model="baseColor" class="col-span-2" />
      </div>

      <template v-for="(color, index) in colorScale" :key="index">
        <div class="grid grid-cols-3 gap-3">
          <span class="flex flex-col place-content-center">{{
            color.step
          }}</span>
          <ColorPicker
            :model-value="color.color"
            @update:model-value="(val) => updateScaleColor(index, val)"
            class="col-span-2"
          />
        </div>
      </template>

      <AppButton
        v-if="colorScale?.length"
        type="warning"
        @click="clearColors"
        class="mt-3"
      >
        {{ __('Clear custom properties', 'uixpress') }}
      </AppButton>
    </div>
  </div>
</template>
